@theme {
  --color-primary: #C9A96E;
  --color-primary-foreground: #000000;
  --color-secondary: #1a1a2e;
  --color-secondary-foreground: #e8dcc8;
  --color-accent: #C9A96E;
  --color-accent-foreground: #000000;
  --color-background: #0a0a0a;
  --color-surface: #111111;
  --color-surface-light: #1a1a1a;
  --color-foreground: #e8dcc8;
  --color-muted: #1a1a1a;
  --color-muted-foreground: #888888;
  --color-border: #222222;
  --color-card: #111111;
  --color-card-foreground: #e8dcc8;
  --color-ring: #C9A96E;
  --color-input: #222222;
  --color-destructive: #EF4444;
  --color-destructive-foreground: #FFFFFF;
  --color-success: #10B981;
  --color-warning: #F59E0B;
  --color-ink-dark: #000000;
}
body {
  background-color: var(--color-background);
  color: var(--color-foreground);
  font-family: 'Inter', sans-serif;
}
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--color-border); border-radius: 3px; }
button, a, input, select, textarea {
  touch-action: manipulation;
  -webkit-tap-highlight-color: transparent;
}
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
.animate-fade-in-up { animation: fadeInUp 0.6s ease-out; }
@keyframes inkDrip {
  0% { height: 0; opacity: 1; }
  100% { height: 100px; opacity: 0; }
}
@keyframes shimmer {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
.animate-shimmer {
  background: linear-gradient(90deg, var(--color-muted) 25%, var(--color-surface-light) 50%, var(--color-muted) 75%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
}
